/*
 * Diagnostic-first taskpane.js
 */

// 1. Instantly attempt to hook up the settings menu (No Office dependency)
document.addEventListener("DOMContentLoaded", function() {
    console.log("DOM fully loaded.");
    
    const settingsBtn = document.getElementById("settingsBtn");
    const menu = document.getElementById("settingsMenu");

    if (settingsBtn && menu) {
        settingsBtn.style.border = "2px solid green"; // Diagnostic indicator
        settingsBtn.addEventListener("click", function() {
            menu.classList.toggle("hidden");
            console.log("Settings menu clicked!");
        });
    } else {
        console.error("DOM elements not found during DOMContentLoaded.");
    }
});

// 2. Initialize Office-specific features ONLY when Office has confirmed it's ready
Office.onReady(function (info) {
    if (info.host === Office.HostType.Excel) {
        console.log("Office.js is fully ready.");
        
        // Turn the settings button background green to confirm Office.js is active
        const settingsBtn = document.getElementById("settingsBtn");
        if (settingsBtn) {
            settingsBtn.style.backgroundColor = "#d4edda"; 
        }

        const tabsToggle = document.getElementById("toggle-sheet-tabs");
        if (tabsToggle) {
            // Check current visual state of tabs
            syncTabs(tabsToggle);

            // Bind change event
            tabsToggle.addEventListener("change", function() {
                toggleTabs(tabsToggle.checked);
            });
        }
    }
});

async function syncTabs(checkbox) {
    try {
        await Excel.run(async (context) => {
            const activeWindow = context.workbook.getActiveWindow();
            activeWindow.load("showWorkbookTabs");
            await context.sync();
            checkbox.checked = activeWindow.showWorkbookTabs;
        });
    } catch (e) {
        console.warn("Failed to sync tabs on startup: ", e);
    }
}

async function toggleTabs(visible) {
    try {
        if (Office.context.requirements.isSetSupported("ExcelApiDesktop", "1.1")) {
            await Excel.run(async (context) => {
                const activeWindow = context.workbook.getActiveWindow();
                activeWindow.showWorkbookTabs = visible;
                await context.sync();
            });
        } else {
            console.warn("ExcelApiDesktop is not supported on this platform.");
        }
    } catch (e) {
        console.error("Error toggling sheet tabs: ", e);
    }
}